  public static final String INSERT_FWC_CANCEL_DTLS = "INSERT INTO CUSTOM_FWC_DETAILS(CATEGORY,SUB_PRODUCT,CIF_ID,BRANCH,ACCT_NUMBER,DEAL_CCY, \tBOOKING_DATE,FWC_AMOUNT,TO_CCY_AMT,DEAL_VALID_FROM,DEAL_VALID_TO,TREASURY_REF_NO,TREASURY_RATE,OUTSTANDING_AMT,LIMIT_ID,WITHOUT_LIMIT, \tAVAILABLE_LIMIT,WASH_RATE,LEI_NUMBER,PL_AMOUNT,CHARGE_AMOUNT,GST_AMOUNT,INSTRUCTIONS,MARGIN,STATUS,INPUT_BY,INPUT_TIMESTAMP,LAST_ACTION,FWC_CONTRACT_NO,CANCELLATION_AMOUNT,TRANS_ID, TRANS_DATE, BOOKING_RATE)\tVALUES(?,?,?,?,?,?,TO_DATE(?,'dd/mm/yyyy'),?,?,TO_DATE(?,'dd/mm/yyyy'),TO_DATE(?,'dd/mm/yyyy'),?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,SYSTIMESTAMP,?,?,?,?,?,?) ";
