  public static final String FETCH_ALL_FWC_DTLS = "SELECT FWC.ID AS ID,FWC.CATEGORY AS CATEGORY,FWC.FWC_CONTRACT_NO AS FWC_CONTRACT_NO,FWC.SUB_PRODUCT AS SUB_PRODUCT,FWC.CIF_ID AS CIF_ID,FWC.BRANCH AS BRANCH,FWC.ACCT_NUMBER AS ACCT_NUMBER,FWC.DEAL_CCY AS DEAL_CCY, FWC.FWC_AMOUNT AS FWC_AMOUNT,TO_CHAR(TO_DATE(FWC.BOOKING_DATE,'DD/MM/YY'),'dd/mm/YYYY') AS BOOKING_DATE,FWC.TO_CCY_AMT AS TO_CCY_AMT, TO_CHAR(TO_DATE(FWC.DEAL_VALID_FROM,'DD/MM/YY'),'dd/mm/YYYY') AS DEAL_VALID_FROM,TO_CHAR(TO_DATE(FWC.DEAL_VALID_TO,'DD/MM/YY'),'dd/mm/YYYY') AS DEAL_VALID_TO, FWC.TREASURY_REF_NO AS TREASURY_REF_NO,FWC.TREASURY_RATE AS TREASURY_RATE,NVL(REGEXP_REPLACE(FWC.FWC_AMOUNT,'[^0-9]+','')-TRSY.DEAL_AMOUNT ,REGEXP_REPLACE(FWC.FWC_AMOUNT,'[^0-9]+',''))||' '||FWC.DEAL_CCY AS OUTSTANDING_AMT,FWC.STATUS AS STATUS FROM CUSTOM_FWC_DETAILS FWC,CUSTOM_TREASURY_INSERT_TBL TRSY WHERE FWC_CONTRACT_NO IS NOT NULL AND FWC.FWC_CONTRACT_NO=TRSY.FWC_REF_NUM(+) AND FWC.CATEGORY=TRSY.HOST_DEAL_CATEGORY(+) ";
