  public static final String FWC_AVAILABLE_AMT_QUERY = "SELECT TO_CHAR(SUM(CASE WHEN HOST_DEAL_CATEGORY='FXRATE' THEN BUY_AMOUNT  WHEN HOST_DEAL_CATEGORY='FWCBOOK' THEN BUY_AMOUNT \tWHEN HOST_DEAL_CATEGORY='FWCUTIL' THEN -BUY_AMOUNT \tWHEN HOST_DEAL_CATEGORY='FWCCANCEL' THEN -SELL_AMOUNT END)) AS BUY_AMOUNT,  TO_CHAR(SUM(CASE WHEN HOST_DEAL_CATEGORY='FXRATE' THEN SELL_AMOUNT  WHEN HOST_DEAL_CATEGORY='FWCBOOK' THEN SELL_AMOUNT \tWHEN HOST_DEAL_CATEGORY='FWCUTIL' THEN -SELL_AMOUNT \tWHEN HOST_DEAL_CATEGORY='FWCCANCEL' THEN -BUY_AMOUNT END)) AS SELL_AMOUNT FROM CUSTOM_TREASURY_INSERT_TBL  WHERE RECORD_STATUS <>'DELETED' AND COUNTERPARTY_STRING IS NOT NULL AND FWC_REF_NUM IS NOT NULL  AND FWC_REF_NUM=? AND COUNTERPARTY_STRING =?";
